// @ts-nocheck
import React, { useMemo } from 'react';
import { Users, X } from 'lucide-react';
import { buildConnectionBreakdown, type ConnectionDbRow } from '../../lib/connection-breakdown';
import { useHorizontalSplit } from '../../lib/usePanelResize';

const CONN_DONUT_COLORS = ['#0ea5e9', '#8b5cf6', '#14b8a6', '#f59e0b', '#ef4444', '#ec4899', '#22c55e', '#6366f1'];

function donutPath(cx: number, cy: number, rO: number, rI: number, startAngle: number, endAngle: number) {
  const a0 = ((startAngle - 90) * Math.PI) / 180;
  const a1 = ((endAngle - 90) * Math.PI) / 180;
  const large = endAngle - startAngle > 180 ? 1 : 0;
  const x0o = cx + rO * Math.cos(a0), y0o = cy + rO * Math.sin(a0);
  const x1o = cx + rO * Math.cos(a1), y1o = cy + rO * Math.sin(a1);
  const x0i = cx + rI * Math.cos(a0), y0i = cy + rI * Math.sin(a0);
  const x1i = cx + rI * Math.cos(a1), y1i = cy + rI * Math.sin(a1);
  return `M ${x0o} ${y0o} A ${rO} ${rO} 0 ${large} 1 ${x1o} ${y1o} L ${x1i} ${y1i} A ${rI} ${rI} 0 ${large} 0 ${x0i} ${y0i} Z`;
}

/** Donut pequeño + leyenda compacta, para ir debajo de "Conexiones totales". */
export function ConnectionDonutMini({ rows = [], loading = false }: { rows?: any[]; loading?: boolean }) {
  const { total, byDatabase } = useMemo(() => buildConnectionBreakdown(rows), [rows]);
  const top = byDatabase.slice(0, 6);
  const othersCount = byDatabase.slice(6).reduce((s, d) => s + d.count, 0);
  const segs = top.map((d) => ({ name: d.name, count: d.count, pct: total ? (d.count / total) * 100 : 0 }));
  if (othersCount > 0) segs.push({ name: 'otros', count: othersCount, pct: total ? (othersCount / total) * 100 : 0 });
  let acc = 0;
  const arcs = segs.map((s, i) => {
    const start = acc;
    acc += s.pct * 3.6;
    return { ...s, start, end: acc, color: CONN_DONUT_COLORS[i % CONN_DONUT_COLORS.length] };
  });
  const cx = 34, cy = 34, rO = 30, rI = 20;
  return (
    <div className="flex items-center gap-2 min-w-0">
      <svg viewBox="0 0 68 68" width="68" height="68" style={{ display: 'block', flexShrink: 0 }}>
        {loading || total === 0 ? (
          <circle cx={cx} cy={cy} r={(rO + rI) / 2} fill="none" stroke="var(--nv-border)" strokeWidth={rO - rI} />
        ) : (
          arcs.map((a) => (
            <path key={a.name} d={donutPath(cx, cy, rO, rI, a.start, Math.min(a.end, 359.99))} fill={a.color} stroke="var(--nv-panel)" strokeWidth={0.5}>
              <title>{`${a.name}: ${a.count} (${a.pct.toFixed(1)}%)`}</title>
            </path>
          ))
        )}
        <text x={cx} y={cy + 4} textAnchor="middle" fontSize={11} fontWeight="700" fill="var(--nv-text)" style={{ fontVariantNumeric: 'tabular-nums' }}>
          {loading ? '…' : total}
        </text>
      </svg>
      <div className="flex flex-col gap-0.5 min-w-0 max-h-[76px] overflow-y-auto">
        {loading ? (
          <span className="text-[9px] text-nv-textSubtle">…</span>
        ) : segs.length === 0 ? (
          <span className="text-[9px] text-nv-textSubtle">Sin conexiones</span>
        ) : (
          segs.map((s, i) => (
            <div key={s.name} className="flex items-center gap-1 text-[9px]" title={`${s.name}: ${s.count} (${s.pct.toFixed(1)}%)`}>
              <span className="w-2 h-2 rounded-sm shrink-0" style={{ background: CONN_DONUT_COLORS[i % CONN_DONUT_COLORS.length] }} />
              <span className="text-nv-textMuted truncate flex-1 min-w-0">{s.name}</span>
              <span className="font-mono tabular-nums text-nv-textSubtle shrink-0">{s.count}</span>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

function DatabaseFilterChips({
  byDatabase,
  selected,
  onToggle,
  onClear,
  maxHeight = 'max-h-20',
  compact = false,
  fill = false,
}: {
  byDatabase: ConnectionDbRow[];
  selected?: Set<string>;
  onToggle?: (name: string) => void;
  onClear?: () => void;
  maxHeight?: string;
  compact?: boolean;
  fill?: boolean;
}) {
  const interactive = typeof onToggle === 'function';

  return (
    <div className={`flex flex-wrap gap-1.5 ${fill ? 'h-full content-between' : 'overflow-y-auto'} ${maxHeight}`}>
      {byDatabase.map((d) => {
        const active = selected?.has(d.name);
        const chipClass = compact
          ? 'px-1.5 py-0 rounded text-[10px]'
          : 'px-2 py-0.5 rounded-full text-2xs';

        if (!interactive) {
          return (
            <span
              key={d.name}
              className={`inline-flex items-center gap-1 ${chipClass} border border-nv-border bg-nv-panel`}
              title={`${d.pct}% del total`}
            >
              <span className={`truncate ${compact ? 'max-w-[5rem]' : 'max-w-[10rem]'} text-nv-text`}>{d.name}</span>
              <span className="font-mono font-semibold tabular-nums text-nv-accent">{d.count}</span>
            </span>
          );
        }

        return (
          <button
            key={d.name}
            type="button"
            onClick={() => onToggle(d.name)}
            className={`inline-flex items-center gap-1.5 ${chipClass} border transition-colors cursor-pointer ${
              active
                ? 'border-nv-accent bg-nv-selected text-nv-accentDark ring-1 ring-nv-accent/40'
                : 'border-nv-border bg-nv-panel text-nv-text hover:border-nv-accent/60 hover:bg-nv-hover'
            }`}
            title={active ? `Quitar filtro: ${d.name}` : `Filtrar por ${d.name} (${d.pct}%)`}
          >
            <span className={`truncate ${compact ? 'max-w-[5rem]' : 'max-w-[10rem]'}`}>{d.name}</span>
            <span className={`font-mono font-semibold tabular-nums ${active ? 'text-nv-accentDark' : 'text-nv-accent'}`}>
              {d.count}
            </span>
          </button>
        );
      })}
      {interactive && selected?.size > 0 && onClear && (
        <button
          type="button"
          onClick={onClear}
          className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-2xs border border-nv-border text-nv-textMuted hover:text-nv-text hover:bg-nv-hover"
          title="Quitar filtros de base de datos"
        >
          <X size={10} />
          Limpiar
        </button>
      )}
    </div>
  );
}

/** Compact KPI card — DPA drill strip. Click opens Process List. */
export function ConnectionBreakdownMetric({
  rows = [],
  loading = false,
  selectedDatabases,
  onToggleDatabase,
  onClearDatabases,
  onOpenProcesses,
}: {
  rows?: any[];
  loading?: boolean;
  selectedDatabases?: Set<string>;
  onToggleDatabase?: (name: string) => void;
  onClearDatabases?: () => void;
  onOpenProcesses?: () => void;
}) {
  const { total, byDatabase } = useMemo(() => buildConnectionBreakdown(rows), [rows]);
  const filteredTotal = selectedDatabases?.size
    ? byDatabase.filter((d) => selectedDatabases.has(d.name)).reduce((s, d) => s + d.count, 0)
    : total;

  const clickable = typeof onOpenProcesses === 'function';

  const inner = (
    <>
      <div className="flex items-center justify-between gap-1">
        <div className="text-[10px] text-nv-textSubtle uppercase tracking-wide">Conexiones totales</div>
        {clickable && !loading && (
          <span className="text-[9px] text-sky-400/70 opacity-0 group-hover:opacity-100 transition-opacity">
            Processes ↗
          </span>
        )}
      </div>
      <div className={`text-sm font-mono font-semibold tabular-nums ${loading ? 'text-nv-textMuted' : 'text-sky-300'}`}>
        {loading ? '…' : (selectedDatabases?.size ? `${filteredTotal} / ${total}` : total)}
      </div>
      {!loading && byDatabase.length > 0 && (
        <div className="mt-1 flex-1 min-h-0 max-h-16 overflow-y-auto" onClick={(e) => e.stopPropagation()}>
          <DatabaseFilterChips
            byDatabase={byDatabase.slice(0, 12)}
            selected={selectedDatabases}
            onToggle={onToggleDatabase}
            onClear={onClearDatabases}
            maxHeight=""
            compact
          />
        </div>
      )}
    </>
  );

  if (!clickable) {
    return (
      <div className="rounded border border-nv-border bg-nv-surface/50 px-2 py-1.5 min-h-[52px] flex flex-col">
        {inner}
      </div>
    );
  }

  return (
    <button
      type="button"
      onClick={onOpenProcesses}
      disabled={loading}
      title="Abrir Process List"
      className="group rounded border border-nv-border bg-nv-surface/50 px-2 py-1.5 min-h-[52px] flex flex-col text-left w-full transition-colors hover:border-sky-600/60 hover:bg-sky-950/25 focus:outline-none focus-visible:ring-2 focus-visible:ring-sky-500/50 disabled:opacity-60 disabled:cursor-wait cursor-pointer"
    >
      {inner}
    </button>
  );
}

/** Header strip — Process List. Split: left subpanel (Conexiones totales + donut) | divisor ajustable | right (chips). */
export function ConnectionBreakdownBar({
  rows = [],
  loading = false,
  selectedDatabases,
  onToggleDatabase,
  onClearDatabases,
}: {
  rows?: any[];
  loading?: boolean;
  selectedDatabases?: Set<string>;
  onToggleDatabase?: (name: string) => void;
  onClearDatabases?: () => void;
}) {
  const { total, byDatabase } = useMemo(() => buildConnectionBreakdown(rows), [rows]);
  const filteredTotal = selectedDatabases?.size
    ? byDatabase.filter((d) => selectedDatabases.has(d.name)).reduce((s, d) => s + d.count, 0)
    : total;
  const split = useHorizontalSplit('nv-processlist-conn-split', 32, { minPct: 24, maxPct: 46, mobileStack: true });

  const numberBlock = (
    <div className="flex items-center gap-2 shrink-0">
      <Users size={14} className="text-sky-400" />
      <div>
        <div className="text-[10px] uppercase tracking-wide text-nv-textSubtle">Conexiones totales</div>
        <div className="text-lg font-mono font-semibold tabular-nums text-sky-300 leading-none">
          {loading ? '…' : (selectedDatabases?.size ? `${filteredTotal} / ${total}` : total)}
        </div>
        {selectedDatabases?.size > 0 && (
          <div className="text-[10px] text-sky-400/80 mt-0.5">
            {selectedDatabases.size} DB filtrada{selectedDatabases.size === 1 ? '' : 's'}
          </div>
        )}
      </div>
    </div>
  );

  const chipsBlock = !loading && byDatabase.length > 0 ? (
    <div className="flex-1 min-w-[12rem] min-h-0 flex flex-col h-full">
      <div className="text-[10px] text-nv-textSubtle mb-1 shrink-0">
        Por base de datos
        {onToggleDatabase && <span className="text-nv-textMuted"> · clic multi-selección</span>}
      </div>
      <DatabaseFilterChips
        byDatabase={byDatabase}
        selected={selectedDatabases}
        onToggle={onToggleDatabase}
        onClear={onClearDatabases}
        fill
      />
    </div>
  ) : null;

  if (split.stacked) {
    return (
      <div className="shrink-0 px-3 py-2 border-b border-nv-border bg-nv-panel/60 flex flex-col gap-2">
        {numberBlock}
        <ConnectionDonutMini rows={rows} loading={loading} />
        {chipsBlock}
      </div>
    );
  }

  return (
    <div
      className="border-b border-nv-border bg-nv-panel/60 flex-1 min-h-0"
      style={{ minHeight: 116 }}
      ref={split.containerRef}
    >
      <div className="flex items-stretch h-full min-h-[116px]">
        <div className="flex flex-col gap-1.5 px-3 py-2 shrink-0 overflow-hidden" style={{ width: `${split.leftPct}%` }}>
          {numberBlock}
          <ConnectionDonutMini rows={rows} loading={loading} />
        </div>
        <div
          className="resizer vertical shrink-0"
          onMouseDown={split.onResizeStart}
          title="Arrastrar para ajustar ancho"
        />
        <div className="flex-1 min-w-0 px-3 py-2 overflow-y-auto flex flex-col">{chipsBlock}</div>
      </div>
    </div>
  );
}
